SELECT year_of_selection, num_students, avg_package
FROM branch_statistics
WHERE year_of_selection = 2019;

SELECT MAX(max_package) AS max_package_2023
FROM placement_statistics
WHERE year_of_selection = 2023;

SELECT branch_id, AVG(avg_package) AS avg_branch_package
FROM branch_statistics
GROUP BY branch_id;

SELECT COUNT(DISTINCT report_id) AS total_reports
FROM placement_reports
WHERE strftime('%Y', report_date) = '2022';

SELECT COUNT(*) 
FROM placement_reports 
WHERE report_type = 'annual';

SELECT DISTINCT c.company_name
FROM companies c
JOIN placement_requests pr ON c.company_id = pr.company_id;

SELECT avg_package AS average_package
FROM placement_statistics
WHERE branch_id = 0 AND year_of_selection = 2020;

SELECT report_type
FROM placement_reports
WHERE report_date LIKE '2022-%';
